import React, { useState } from "react";
import "./CourseTimetable.css";

function CourseTimetable() {
  const [courseId, setCourseId] = useState("");
  const [schedule, setSchedule] = useState("");
  const [roomNo, setRoomNo] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log({ courseId, schedule, roomNo });
  };

  return (
    <form className="timetable-form" onSubmit={handleSubmit}>
      <label>Course ID</label>
      <input type="text" value={courseId} onChange={(e) => setCourseId(e.target.value)} required />
      <label>Schedule</label>
      <input type="text" value={schedule} onChange={(e) => setSchedule(e.target.value)} required />
      <label>Room No</label>
      <input type="text" value={roomNo} onChange={(e) => setRoomNo(e.target.value)} required />
      <button type="submit">Add Timetable</button>
    </form>
  );
}

export default CourseTimetable;
